using Microsoft.ML.Data;

namespace TicketClassifier.Models;

/// <summary>
/// Input schema matching the training CSV.
/// </summary>
public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

/// <summary>
/// ML.NET prediction output.
/// </summary>
public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class TicketClassificationResult
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidences { get; set; } = new();
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

/// <summary>
/// Trains the ticket classifier at startup and saves the model to disk.
/// Also logs evaluation metrics.
/// </summary>
public class ModelTrainingService : IHostedService
{
    private readonly ILogger<ModelTrainingService> _logger;
    private readonly string _dataPath;
    private readonly string _modelPath;

    public ModelTrainingService(ILogger<ModelTrainingService> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public Task StartAsync(CancellationToken cancellationToken)
    {
        TrainAndEvaluate();
        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;

    private void TrainAndEvaluate()
    {
        var mlContext = new MLContext(seed: 42);

        // Load data
        var data = mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Split for evaluation (80/20)
        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Build pipeline: featurize text columns, combine with Priority, classify
        var pipeline = mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation("=== Model Evaluation Metrics ===");
        _logger.LogInformation("  MacroAccuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("  MicroAccuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("  LogLoss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("  LogLossReduction: {LogLossReduction:F4}", metrics.LogLossReduction);

        // Retrain on full dataset for production model
        var productionModel = pipeline.Fit(data);
        mlContext.Model.Save(productionModel, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", _modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;

    // Category labels in the order the model scores them
    private static readonly string[] Categories = ["Billing", "General", "Technical"];

    public TicketController(PredictionEnginePool<TicketData, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public ActionResult<TicketClassificationResult> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionPool.Predict(input);

        var confidences = new Dictionary<string, float>();
        for (int i = 0; i < Math.Min(Categories.Length, prediction.Score.Length); i++)
            confidences[Categories[i]] = prediction.Score[i];

        return Ok(new TicketClassificationResult
        {
            PredictedCategory = prediction.Category,
            Confidences = confidences,
        });
    }
}

